import { useState, useRef, useEffect } from 'react';
import { getApiBase } from '../utils/platform';

const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  surface2: '#111A24',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#22C55E',
  blue: '#60A5FA',
  purple: '#A78BFA',
};
const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

/**
 * AIExplainButton — Reusable inline button that calls /api/assistant/explain
 * and shows a popover with the AI explanation.
 *
 * Props:
 *   explainType: 'position' | 'strategy' | 'ml'
 *   ref: symbol, strategy key, or model name
 *   label: button text (default: "AI Explain")
 *   style: extra styles for the button
 */
export default function AIExplainButton({ explainType, refId, label = 'AI Explain', style = {} }) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [explanation, setExplanation] = useState(null);
  const [error, setError] = useState(null);
  const popRef = useRef(null);

  // Close popover on outside click
  useEffect(() => {
    if (!open) return;
    const handler = (e) => {
      if (popRef.current && !popRef.current.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  const handleClick = async (e) => {
    e.stopPropagation();
    if (open) {
      setOpen(false);
      return;
    }
    setOpen(true);
    if (explanation) return; // Already fetched

    setLoading(true);
    setError(null);
    try {
      let token; try { token = localStorage.getItem('aura_token'); } catch {}
      const res = await fetch(`${getApiBase()}/assistant/explain`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
        body: JSON.stringify({ explain_type: explainType, ref: refId }),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        if (res.status === 401 || res.status === 403) throw new Error('Sign in to use AI Explain');
        throw new Error(data.detail || `HTTP ${res.status}`);
      }
      const data = await res.json();
      setExplanation(data.explanation);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ position: 'relative', display: 'inline-block' }} ref={popRef}>
      <button
        onClick={handleClick}
        style={{
          fontFamily: mono,
          fontSize: 11,
          fontWeight: 600,
          padding: '4px 10px',
          borderRadius: 6,
          border: `1px solid ${C.purple}40`,
          background: `${C.purple}15`,
          color: C.purple,
          cursor: 'pointer',
          transition: 'all 0.15s',
          whiteSpace: 'nowrap',
          ...style,
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = `${C.purple}25`;
          e.currentTarget.style.borderColor = C.purple;
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = `${C.purple}15`;
          e.currentTarget.style.borderColor = `${C.purple}40`;
        }}
        title="Get AI explanation"
      >
        {label}
      </button>

      {open && (
        <div
          style={{
            position: 'absolute',
            top: '100%',
            right: 0,
            marginTop: 8,
            width: 380,
            maxHeight: 320,
            overflowY: 'auto',
            background: C.surface,
            border: `1px solid ${C.border}`,
            borderRadius: 10,
            padding: 16,
            boxShadow: '0 8px 32px rgba(0,0,0,0.4)',
            zIndex: 9999,
          }}
        >
          {/* Header */}
          <div style={{
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            marginBottom: 12, paddingBottom: 8, borderBottom: `1px solid ${C.border}`,
          }}>
            <span style={{ fontFamily: body, fontSize: 13, fontWeight: 600, color: C.purple }}>
              AI Explanation
            </span>
            <button
              onClick={(e) => { e.stopPropagation(); setOpen(false); }}
              style={{
                background: 'none', border: 'none', color: C.textSecondary,
                cursor: 'pointer', fontSize: 14, lineHeight: 1, padding: 4,
              }}
            >
              x
            </button>
          </div>

          {/* Content */}
          {loading && (
            <div style={{ fontFamily: mono, fontSize: 13, color: C.textSecondary, textAlign: 'center', padding: 20 }}>
              Analyzing...
            </div>
          )}
          {error && (
            <div style={{ fontFamily: mono, fontSize: 13, color: '#EF4444' }}>
              {typeof error === 'string' ? error : error?.message || 'An error occurred'}
            </div>
          )}
          {explanation && (
            <div style={{
              fontFamily: body, fontSize: 13, lineHeight: 1.6,
              color: C.textPrimary, whiteSpace: 'pre-wrap',
            }}>
              {explanation}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
